from collections import deque

class Solution:
    def minDays(self, n: int) -> int:
        dist = {n: 0}
        q = deque([n])
        while q:
            cur = q.popleft()
            if cur == 0:
                return dist[cur]
            nxts = [cur - 1]
            if cur % 2 == 0:
                nxts.append(cur // 2)
            if cur % 3 == 0:
                nxts.append(cur - 2 * (cur // 3))
            for nxt in nxts:
                if nxt not in dist:
                    dist[nxt] = dist[cur] + 1
                    q.append(nxt)
        return dist[0]

