class Solution:
    def minDays(self, n: int) -> int:
        memo = {0: 0, 1: 1}

        def dp(n):
            if n in memo:
                return memo[n]
            result = 1 + min(n % 2 + dp(n // 2), n % 3 + dp(n // 3))
            memo[n] = result
            return result

        return dp(n)

