var minDays = function(n) {
    const memo = new Map([[0, 0], [1, 1]]);

    function dp(n) {
        if (memo.has(n)) return memo.get(n);
        const result = 1 + Math.min(
            (n % 2) + dp(Math.floor(n / 2)),
            (n % 3) + dp(Math.floor(n / 3))
        );
        memo.set(n, result);
        return result;
    }

    return dp(n);
};
